import heapq

def k_smallest(nums, k):
    return heapq.nsmallest(k, nums)

import heapq

def kth_largest(nums, k):
    h = []
    for x in nums:
        heapq.heappush(h, x)
        if len(h) > k:
            heapq.heappop(h)
    return h[0]

